749	  /* ── Reply flow ────────────────────────────────────────────── */
750	
751	  const openReply = $((noteId: string) => {
752	    store.replyNoteId = noteId;
753	    store.replyingTo = noteId;
754	    store.replyDraft = "";
755	  });
756	
757	  const cancelReply = $(() => {
758	    store.replyNoteId = null;
759	    store.replyingTo = null;
760	    store.replyDraft = "";
761	  });
762	
763	  const emitReplyThread = $((noteId: string) => {
764	    window.dispatchEvent(
765	      new CustomEvent("twyne:persona-reply-thread", {
766	        detail: {
767	          noteId,
768	          replies: store.repliesByNote[noteId] ?? [],
769	        },
770	      }),
771	    );
772	  });
773	
774	  const submitReply = $(async (noteId: string, askPersona: boolean) => {
775	    const text = store.replyDraft.trim();
776	    if (!text) return;
777	    if (store.groupByPersona) {
778	      const note = store.feedback.find((f) => f.noteId === noteId);
779	      const latestForPersona = note
780	        ? store.feedback
781	            .filter((f) => f.personaId === note.personaId)
782	            .sort((a, b) => b.timestamp - a.timestamp)[0]
783	        : null;
784	      if (note && latestForPersona?.noteId !== noteId) {
785	        store.groupByPersona = false;
786	      }
787	    }
788	    const userReply: PersonaReply = {
789	      id: `preply-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
790	      noteId,
791	      author: "You",
792	      authorKind: "user",
793	      text,
794	      timestamp: Date.now(),
795	    };
796	    const updated = [...(store.repliesByNote[noteId] ?? []), userReply];
797	    store.repliesByNote = { ...store.repliesByNote, [noteId]: updated };
798	    void emitReplyThread(noteId);
799	    await addPersonaReplyLocally(userReply);
800	    const client =
