130	function pickAnchorSentences(
131	  text: string,
132	  personaIds: string[],
133	): Record<string, string> {
134	  const sentences: string[] = [];
135	  for (const paragraph of text.split(/\n+/)) {
136	    const matches = paragraph.match(/[^.!?]+[.!?]+(?=\s|$)/g) ?? [];
137	    for (const raw of matches) {
138	      const sentence = raw.trim();
139	      if (sentence.split(/\s+/).length >= 6) sentences.push(sentence);
140	    }
141	  }
142	  if (sentences.length === 0) return {};
143	
144	  const used = new Set<number>();
145	  const take = (start: number): string | undefined => {
146	    for (let step = 0; step < sentences.length; step++) {
147	      const i = (start + step) % sentences.length;
148	      if (!used.has(i)) {
149	        used.add(i);
150	        return sentences[i];
151	      }
152	    }
153	    return undefined;
154	  };
155	
156	  const longest = sentences.reduce(
157	    (best, s, i) => (s.length > sentences[best].length ? i : best),
158	    0,
159	  );
160	  const evidence = sentences.findIndex((s) =>
161	    /\d|percent|study|studies|research|according to|evidence/i.test(s),
162	  );
163	  const claim = sentences.findIndex((s) =>
164	    /\b(must|should|clearly|obviously|always|never|every|all of|no one|undeniabl)/i.test(
165	      s,
166	    ),
167	  );
168	
169	  const preferred: Record<string, number> = {
170	    reader: 0,
171	    editor: longest,
172	    devil: claim >= 0 ? claim : Math.floor(sentences.length / 2),
173	    scholar: evidence >= 0 ? evidence : Math.floor((sentences.length * 2) / 3),
174	    angel: Math.floor(sentences.length / 3),
175	  };
176	
177	  const result: Record<string, string> = {};
178	  for (const id of personaIds) {
179	    if (id in preferred) {
180	      const s = take(preferred[id]);
181	      if (s) result[id] = s;
182	    }
183	  }
184	  let cursor = 0;
185	  for (const id of personaIds) {
186	    if (result[id] !== undefined || id in preferred) continue;
187	    const s = take(cursor++ % sentences.length);
188	    if (s) result[id] = s;
189	  }
190	  return result;
191	}
