        void loadUserComments().then((all) => {
          if (initialComments) return;
          store.comments = all;
        });
      };
      const onScroll = (e: Event) => {
        const detail = (e as CustomEvent).detail;
        const id = typeof detail === "string" ? detail : detail?.id;
        if (!id) return;
