function escapeRegExp(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/** Persona ids @-mentioned by name (whole word) anywhere in the text. */
function mentionedPersonaIds(text: string, personas: Persona[]): string[] {
  const ids: string[] = [];
  for (const p of personas) {
    const re = new RegExp(`@${escapeRegExp(p.name)}\\b`, "i");
    if (re.test(text)) ids.push(p.id);
  }
  return ids;
}

