1	import { component$, useStore, useVisibleTask$, $ } from "@builder.io/qwik";
2	import { useConvexClient } from "../../utils/convex-context";
3	import type { ProjectBrief, Persona } from "../../types";
4	import {
5	  type UserComment,
6	  type UserCommentReply,
7	  loadUserComments,
8	  upsertUserComment,
9	  appendUserCommentReply,
10	  toggleUserCommentResolved,
11	  deleteUserComment,
12	} from "../../utils/user-comments";
13	import { PERSONAS as DEFAULT_PERSONAS } from "../../utils/personas";
14	import { loadPersonasFromIdb, loadAiSettingsFromIdb } from "../../utils/idb";
15	import { api } from "../../../convex/_generated/api";
16	import type { AiSettings } from "../../types";
17	import {
18	  hasConfiguredAiProvider,
19	  runClientAgent,
20	  normalizeAiSettings,
21	} from "../../utils/ai-client";
22	
23	interface CommentsStore {
24	  comments: UserComment[];
25	  newCommentText: string;
26	  replyingTo: string | null;
27	  /** Per-comment reply drafts (keyed by comment id). */
28	  replyDrafts: Record<string, string>;
29	  askPersonaFor: string | null;
30	  askPersonaId: string | null;
31	  isAskingEditor: boolean;
32	  askError: string | null;
33	  personas: Persona[];
34	  aiSettings: AiSettings | null;
35	  /** Ids of threads whose anchor mark is gone from the doc. */
36	  ghostIds: Set<string>;
37	  /** Show only ghosts? Off by default; the chip flips it. */
38	  ghostsOnly: boolean;
39	  /** Which textarea is showing an @-mention dropdown ("new" or a comment id). */
40	  mentionTarget: "new" | string | null;
41	  /** The partial name typed after "@". */
42	  mentionQuery: string;
43	}
44	
45	interface CommentsPanelProps {
46	  brief: ProjectBrief | null;
47	  activeFolioId: string | null;
48	  /** Seed notes, for tests and isolated previews. Skips persisted storage when set. */
49	  initialComments?: UserComment[];
50	}
51	
52	export const CommentsPanel = component$(
53	  ({ brief, activeFolioId, initialComments }: CommentsPanelProps) => {
54	    const clientSig = useConvexClient();
55	    const store = useStore<CommentsStore>({
56	      comments: initialComments ?? [],
57	      newCommentText: "",
58	      replyingTo: null,
59	      replyDrafts: {},
60	      askPersonaFor: null,
61	      askPersonaId: null,
62	      isAskingEditor: false,
63	      askError: null,
64	      personas: DEFAULT_PERSONAS,
65	      aiSettings: null,
66	      ghostIds: new Set<string>(),
67	      ghostsOnly: false,
68	      mentionTarget: null,
69	      mentionQuery: "",
70	    });
71	
72	  // eslint-disable-next-line qwik/no-use-visible-task
73	  useVisibleTask$(async () => {
74	    if (initialComments) return;
75	    store.comments = await loadUserComments();
76	    const custom = await loadPersonasFromIdb();
77	    if (custom && custom.length > 0) store.personas = custom;
78	    const aiRaw = await loadAiSettingsFromIdb();
79	    store.aiSettings = normalizeAiSettings(aiRaw);
80	  });
81	
82	    // Refresh when a comment is filed or replied to elsewhere in the editor.
83	    // eslint-disable-next-line qwik/no-use-visible-task
84	    useVisibleTask$(() => {
85	      const refresh = () => {
86	        void loadUserComments().then((all) => {
87	          if (initialComments) return;
88	          store.comments = all;
89	        });
90	      };
91	      const onScroll = (e: Event) => {
92	        const detail = (e as CustomEvent).detail;
93	        const id = typeof detail === "string" ? detail : detail?.id;
94	        if (!id) return;
95	        const el = document.querySelector(`[data-comment-id="${id}"]`);
96	        el?.scrollIntoView({ behavior: "smooth", block: "center" });
97	      };
98	      window.addEventListener("twyne:user-comments-changed", refresh);
99	      window.addEventListener("twyne:scroll-to-comment", onScroll);
100	      return () => {
101	        window.removeEventListener("twyne:user-comments-changed", refresh);
102	        window.removeEventListener("twyne:scroll-to-comment", onScroll);
103	      };
104	    });
105	
106	    const addComment = $(async () => {
107	      if (!store.newCommentText.trim()) return;
108	      const comment: UserComment = {
109	        id: `c-${Date.now()}`,
110	        folioId: activeFolioId ?? "",
111	        text: store.newCommentText,
112	        author: "You",
113	        resolved: false,
114	        createdAt: Date.now(),
115	        updatedAt: Date.now(),
116	        replies: [],
117	      };
118	      const all = await upsertUserComment(comment);
119	      store.comments = all;
120	      store.newCommentText = "";
121	      window.dispatchEvent(new CustomEvent("twyne:user-comments-changed"));
122	      for (const personaId of mentionedPersonaIds(comment.text, store.personas)) {
123	        void askEditor(comment.id, personaId);
124	      }
125	    });
126	
127	    const addReply = $(async (commentId: string, text: string) => {
128	      if (!text.trim()) return;
129	      const reply: UserCommentReply = {
130	        id: `r-${Date.now()}`,
131	        author: "You",
132	        authorKind: "user",
133	        text,
134	        createdAt: Date.now(),
135	      };
136	      const all = await appendUserCommentReply(commentId, reply);
137	      store.comments = all;
138	      store.replyingTo = null;
139	      window.dispatchEvent(new CustomEvent("twyne:user-comments-changed"));
140	      for (const personaId of mentionedPersonaIds(text, store.personas)) {
141	        void askEditor(commentId, personaId);
142	      }
143	    });
144	
145	    const resolveComment = $(async (commentId: string) => {
146	      const all = await toggleUserCommentResolved(commentId);
147	      store.comments = all;
148	      window.dispatchEvent(new CustomEvent("twyne:user-comments-changed"));
149	    });
150	
151	    const deleteComment = $(async (commentId: string) => {
152	      const all = await deleteUserComment(commentId);
153	      store.comments = all;
154	      window.dispatchEvent(new CustomEvent("twyne:user-comments-changed"));
155	    });
156	
157	    /**
158	     * Ask an editor to weigh in on a comment thread. Pulls the persona's
159	     * voice, anchors the question on the quoted passage, and appends the
160	     * response as a persona-kind reply so the editor's colour + voice are
161	     * preserved.
162	     */
163	    const askEditor = $(async (commentId: string, personaIdOverride?: string) => {
164	      const personaId = personaIdOverride ?? store.askPersonaId;
165	      if (!personaId) return;
166	      const comment = store.comments.find((c) => c.id === commentId);
167	      if (!comment) return;
168	      const persona = store.personas.find((p) => p.id === personaId);
169	      if (!persona) return;
170	      const client = clientSig.value;
171	
172	      // Build the message — anchor + thread, mirror the inline-note call shape.
173	      const userMessage = [
174	        comment.anchor ? `On the passage: «${comment.anchor}»` : null,
175	        `The writer's note: ${comment.text}`,
176	        comment.replies.length > 0
177	          ? `The thread so far: ${comment.replies
178	              .map((r) => `${r.author}: ${r.text}`)
179	              .join(" · ")}`
180	          : null,
181	        "Reply as if you are this editor — one paragraph, your voice.",
182	      ]
183	        .filter(Boolean)
184	        .join("\n\n");
185	
186	      const priorMessages = comment.replies.map((r) => ({
187	        author: r.authorKind,
188	        text: r.text,
189	      }));
190	
191	      store.isAskingEditor = true;
192	      store.askError = null;
193	      try {
194	        let replyText = "";
195	
196	        // ── Try client-side AI first (BYOK) ─────────────────────────
197	        const settings = store.aiSettings;
198	        if (hasConfiguredAiProvider(settings) && settings) {
199	          try {
200	            const res = await runClientAgent(
201	              "comment-reply",
202	              {
203	                persona: {
204	                  id: persona.id,
205	                  name: persona.name,
206	                  role: persona.role,
207	                  description: persona.description,
208	                  focus: persona.focus,
209	                  color: persona.color,
