803	                  </button>
804	                </div>
805	              </div>
806	            </div>
807	          ))}
808	        </div>
809	      </div>
810	    );
811	  },
812	);
813	
814	function getTimeAgo(timestamp: number): string {
815	  const seconds = Math.floor((Date.now() - timestamp) / 1000);
816	  if (seconds < 60) return "just now";
817	  const minutes = Math.floor(seconds / 60);
818	  if (minutes < 60) return `${minutes}m ago`;
819	  const hours = Math.floor(minutes / 60);
820	  if (hours < 24) return `${hours}h ago`;
821	  return `${Math.floor(hours / 24)}d ago`;
822	}
823	
824	function truncate(s: string, n: number): string {
825	  if (s.length <= n) return s;
826	  return s.slice(0, n - 1) + "…";
827	}
828	
829	/** The partial name being typed after a trailing "@", if any. */
830	function activeMentionQuery(value: string): string | null {
831	  const match = value.match(/@([A-Za-z]*)$/);
832	  return match ? match[1] : null;
833	}
834	
835	function escapeRegExp(s: string): string {
836	  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
837	}
838	
839	/** Persona ids @-mentioned by name (whole word) anywhere in the text. */
840	function mentionedPersonaIds(text: string, personas: Persona[]): string[] {
841	  const ids: string[] = [];
842	  for (const p of personas) {
843	    const re = new RegExp(`@${escapeRegExp(p.name)}\\b`, "i");
844	    if (re.test(text)) ids.push(p.id);
845	  }
846	  return ids;
847	}
848	
849	/** Last-resort reply if the agent call fails. */
850	function fallbackReply(persona: Persona, c: UserComment): string {
851	  return `${persona.name}: I would push you on this — ${c.text.slice(0, 60)}${c.text.length > 60 ? "…" : ""}. What's the strongest counter-argument?`;
852	}
853	
854	function getCommentPlaceholder(brief: ProjectBrief | null): string {
855	  if (!brief) return "Add a comment...";
856	  return `Note for ${brief.answers.audience}...`;
857	}
