56	interface CommentsPanelProps {
57	  brief: ProjectBrief | null;
58	  activeFolioId: string | null;
59	  /** Seed notes, for tests and isolated previews. Skips persisted storage when set. */
60	  initialComments?: UserComment[];
61	}
62	
63	export const CommentsPanel = component$(
64	  ({ brief, activeFolioId, initialComments }: CommentsPanelProps) => {
65	    const clientSig = useConvexClient();
66	    const store = useStore<CommentsStore>({
67	      comments: initialComments ?? [],
68	      newCommentText: "",
69	      replyingTo: null,
70	      replyDrafts: {},
71	      askPersonaFor: null,
72	      askPersonaId: null,
73	      isAskingEditor: false,
74	      askError: null,
75	      personas: DEFAULT_PERSONAS,
76	      aiSettings: null,
77	      ghostIds: new Set<string>(),
78	      ghostsOnly: false,
79	      mentionTarget: null,
80	      mentionQuery: "",
81	    });
82	
83	  // eslint-disable-next-line qwik/no-use-visible-task
84	  useVisibleTask$(async () => {
85	    if (initialComments) return;
86	    store.comments = await loadUserComments();
87	    const custom = await loadPersonasFromIdb();
88	    if (custom && custom.length > 0) store.personas = custom;
89	    const aiRaw = await loadAiSettingsFromIdb();
90	    store.aiSettings = normalizeAiSettings(aiRaw);
91	  });
92	
93	    // Refresh when a comment is filed or replied to elsewhere in the editor.
94	    // eslint-disable-next-line qwik/no-use-visible-task
95	    useVisibleTask$(() => {
96	      const refresh = () => {
97	        void loadUserComments().then((all) => {
98	          if (initialComments) return;
99	          store.comments = all;
100	        });
101	      };
102	      const onScroll = (e: Event) => {
103	        const detail = (e as CustomEvent).detail;
104	        const id = typeof detail === "string" ? detail : detail?.id;
105	        if (!id) return;
106	        const el = document.querySelector(`[data-comment-id="${id}"]`);
107	        el?.scrollIntoView({ behavior: "smooth", block: "center" });
108	      };
109	      window.addEventListener("twyne:user-comments-changed", refresh);
110	      window.addEventListener("twyne:scroll-to-comment", onScroll);
111	      return () => {
