62	   * Human collaborators taggable alongside personas. Not wired to a data
63	   * source yet — pass the result of `api.collaboration.getCollaborators`
64	   * (mapped to `Mentionable`s with `kind: "collaborator"`) once a folio is
65	   * shared, and the @-mention flow picks them up with no further changes.
66	   */
67	  collaborators?: Mentionable[];
68	}
