70	export const CommentsPanel = component$(
71	  ({
72	    brief,
73	    activeFolioId,
74	    initialComments,
75	    collaborators,
76	  }: CommentsPanelProps) => {
77	    const clientSig = useConvexClient();
78	    const store = useStore<CommentsStore>({
79	      comments: initialComments ?? [],
