105	    // Refresh when a comment is filed or replied to elsewhere in the editor.
106	    // eslint-disable-next-line qwik/no-use-visible-task
107	    useVisibleTask$(() => {
108	      const refresh = () => {
109	        void loadUserComments().then((all) => {
110	          if (initialComments) return;
111	          store.comments = all;
112	        });
113	      };
114	      const onScroll = (e: Event) => {
115	        const detail = (e as CustomEvent).detail;
116	        const id = typeof detail === "string" ? detail : detail?.id;
117	        if (!id) return;
