    };
    localStorage.setItem("twyne-project-brief", JSON.stringify(brief));
  });
  await page.goto("http://localhost:5183/editor/");
  await page.waitForTimeout(2500);

  // Click the layout button, try to select "wide"
  try {
    await page.click('button:has-text("layout")', { timeout: 3000 });
    await page.waitForTimeout(400);
    await page.click('text=/wide/i', { timeout: 3000 });
    await page.waitForTimeout(400);
  } catch (e) {
    console.log(label, "layout click failed:", e.message);
