import { chromium } from "playwright";

const browser = await chromium.launch();

async function check(width, height, label, panelWidth) {
  const page = await browser.newPage({ viewport: { width, height } });
  await page.goto("http://localhost:5183/editor/");
  await page.evaluate(() => {
    const brief = {
      answers: {
        workingTitle: "Layout Test",
        format: "Essay",
        audience: "Reader",
        goal: "Test",
        tone: "Clear",
        constraints: "None",
        successSignal: "Signal",
      },
      attachments: [],
      completedAt: Date.now(),
      updatedAt: Date.now(),
    };
    localStorage.setItem("twyne-project-brief", JSON.stringify(brief));
  });
  await page.goto("http://localhost:5183/editor/");
  await page.waitForTimeout(2500);

  // Force wide doc width directly + simulate the panel being dragged to panelWidth
  // by dragging the resize handle (the thin bar right before the aside).
  const handle = await page.$('div[title="Drag to resize"]');
  if (handle) {
    const box = await handle.boundingBox();
    if (box) {
      await page.mouse.move(box.x + 2, box.y + box.height / 2);
      await page.mouse.down();
      // starting rightPanelWidth default 340; dragging left increases width
      const targetDeltaX = -(panelWidth - 340);
      await page.mouse.move(
        box.x + 2 + targetDeltaX,
        box.y + box.height / 2,
        { steps: 10 },
      );
      await page.mouse.up();
    }
  }
  await page.evaluate(() => {
    document.documentElement.style.setProperty("--doc-width", "62rem");
  });
  await page.waitForTimeout(300);

  await page.screenshot({
    path: `/tmp/claude-1000/-home-diogenes-Projects-twyne/5c609ace-fa9b-4c1d-825a-cc1d085622b6/scratchpad/editor-${label}.png`,
    fullPage: false,
  });

