    scrollWidth: document.documentElement.scrollWidth,
    innerWidth: window.innerWidth,
    docWidth: getComputedStyle(document.documentElement).getPropertyValue(
      "--doc-width",
    ),
  }));
  console.log(label, JSON.stringify(info));
  await page.close();
}

