.landing-quote {
  font-family: var(--font-display);
  font-style: italic;
  color: var(--color-ink-light);
}

/* ── Persona margin notes — inline marks in the manuscript ── */
.twyne-persona-note {
  --note-color: var(--color-vermilion);
  cursor: pointer;
  background: color-mix(in srgb, var(--note-color) 11%, transparent);
  border-bottom: 2px dotted var(--note-color);
  transition: background 0.15s ease;
}
.twyne-persona-note:hover {
  background: color-mix(in srgb, var(--note-color) 22%, transparent);
}
.twyne-persona-note.is-flashing {
  animation: persona-note-flash 1.4s ease-out;
}
@keyframes persona-note-flash {
  0%,
  35% {
    background: color-mix(in srgb, var(--note-color) 38%, transparent);
  }
  100% {
    background: color-mix(in srgb, var(--note-color) 11%, transparent);
  }
}

.persona-note-card {
  position: fixed;
  z-index: var(--z-dropdown);
  width: min(20.5rem, calc(100vw - 1rem));
  padding: 0.85rem 1rem 1rem;
  background: var(--color-paper-soft);
  border: 1px solid
    color-mix(in srgb, var(--note-color) 45%, var(--color-paper-3));
  border-radius: 2px;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 18px 36px -20px rgba(31, 27, 22, 0.5);
  animation: persona-note-pop 0.18s cubic-bezier(0.22, 1, 0.36, 1);
}
@keyframes persona-note-pop {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
