import { chromium } from "playwright";

const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1024, height: 800 } });
page.on("console", (msg) => {
  if (msg.type() === "error") console.log("PAGE ERROR:", msg.text());
});
await page.goto("http://localhost:5183/editor/");
await page.evaluate(() => {
  const brief = {
    answers: {
      workingTitle: "Layout Test",
      format: "Essay",
      audience: "Reader",
      goal: "Test",
      tone: "Clear",
      constraints: "None",
      successSignal: "Signal",
    },
    attachments: [],
    completedAt: Date.now(),
    updatedAt: Date.now(),
  };
  localStorage.setItem("twyne-project-brief", JSON.stringify(brief));
});
await page.goto("http://localhost:5183/editor/");
await page.waitForTimeout(2500);

// Drag panel to max, then shrink viewport to see the clamp kick in.
const handle = await page.$('div[title="Drag to resize"]');
const box = await handle.boundingBox();
await page.mouse.move(box.x + 2, box.y + box.height / 2);
await page.mouse.down();
await page.mouse.move(box.x - 400, box.y + box.height / 2, { steps: 10 });
await page.mouse.up();
await page.waitForTimeout(200);

const afterDrag = await page.evaluate(() => document.documentElement.scrollWidth);
console.log("after drag, scrollWidth:", afterDrag, "innerWidth:", 1024);

await page.setViewportSize({ width: 700, height: 800 });
await page.waitForTimeout(400);
const afterShrink = await page.evaluate(() => ({
  scrollWidth: document.documentElement.scrollWidth,
  innerWidth: window.innerWidth,
}));
console.log("after shrink to 700:", JSON.stringify(afterShrink));
await page.screenshot({
  path: "/tmp/claude-1000/-home-diogenes-Projects-twyne/5c609ace-fa9b-4c1d-825a-cc1d085622b6/scratchpad/editor-narrow-clamped.png",
});

// Now toggle zen mode
await page.setViewportSize({ width: 1024, height: 800 });
await page.waitForTimeout(300);
await page.click('button[aria-label="Toggle zen mode"]');
await page.waitForTimeout(400);
await page.screenshot({
  path: "/tmp/claude-1000/-home-diogenes-Projects-twyne/5c609ace-fa9b-4c1d-825a-cc1d085622b6/scratchpad/editor-zen-mode.png",
});
const zenState = await page.evaluate(() => ({
  hasZenClass: !!document.querySelector(".twyne-editor.zen-mode"),
}));
console.log("zen state:", JSON.stringify(zenState));

await browser.close();

